/**
 * Lightweight i18n for JORINOVA NEXUS — English ↔ French ↔ Kinyarwanda.
 *
 * Single translation dictionary keyed by short slugs. Use the `useT()`
 * hook in any client component:
 *
 *   const t = useT()
 *   <h1>{t('dashboard.welcome', { name: user.first_name })}</h1>
 *
 * Default language: 'en'. Switching is driven by I18nProvider which
 * reads `user.preferred_language` from AuthProvider.
 *
 * Missing-key behaviour: returns the key itself so dev can spot gaps
 * during testing but the UI never crashes.
 */

export type Lang = 'en' | 'fr' | 'rw'

export const LANGUAGES: Record<Lang, { label: string; flag: string }> = {
  en: { label: 'English',    flag: '🇬🇧' },
  fr: { label: 'Français',   flag: '🇫🇷' },
  rw: { label: 'Kinyarwanda', flag: '🇷🇼' },
}

