  // ── Help & Support ─────────────────────────────────────────────────────
  'help.crumb':         { en: 'HELP & SUPPORT', fr: 'AIDE & SUPPORT', rw: 'UBUFASHA' },
  'help.title':         { en: 'TRAINING VIDEOS & GUIDED WALKTHROUGHS', fr: 'VIDÉOS DE FORMATION & GUIDES', rw: 'AMASHUSHO Y’AMAHUGURWA' },
  'help.intro_1':       { en: 'Every voice-narrated walkthrough lives here. Click any tile to launch the in-app assistant — say', fr: 'Toutes les démonstrations narrées sont ici. Cliquez sur une tuile pour lancer l’assistant — dites', rw: 'Ibyerekane byose biri hano. Kanda kugira ngo utangize umufasha — vuga' },
  'help.intro_play':    { en: 'to play,',     fr: 'pour lancer,', rw: 'gutangira,' },
  'help.intro_next':    { en: 'to advance.',  fr: 'pour avancer.', rw: 'gukomeza.' },
  'help.search':        { en: 'Search scenarios (e.g. blood bank, OCR, malaria)', fr: 'Rechercher des scénarios (ex. banque de sang, OCR, paludisme)', rw: 'Shakisha ibyerekane (urugero banki y’amaraso, OCR)' },
  'help.count':         { en: '{n} of {m}',   fr: '{n} sur {m}',  rw: '{n} muri {m}' },
  'help.loading':       { en: 'Loading scenarios…', fr: 'Chargement des scénarios…', rw: 'Birapakira ibyerekane…' },
  'help.no_match':      { en: 'No scenarios match “{q}”.', fr: 'Aucun scénario ne correspond à « {q} ».', rw: 'Nta byerekane bihuye na “{q}”.' },
  'help.tile_meta':     { en: '▶ {min} min · {steps} steps', fr: '▶ {min} min · {steps} étapes', rw: '▶ {min} min · intambwe {steps}' },
  'help.faq':           { en: 'FREQUENTLY ASKED', fr: 'QUESTIONS FRÉQUENTES', rw: 'IBIBAZWA KENSHI' },
  'help.faq1.q':        { en: 'The voice assistant doesn’t speak — what should I check?', fr: 'L’assistant vocal ne parle pas — que vérifier ?', rw: 'Umufasha w’ijwi ntavuga — nareba iki?' },
  'help.faq1.a':        { en: 'Click 🔊 Voice in the runner header (the mute toggle). On first load, browsers wait for a user interaction before allowing audio. Volume must be up.', fr: 'Cliquez sur 🔊 Voix dans l’en-tête (le bouton de sourdine). Au premier chargement, les navigateurs attendent une interaction avant d’autoriser l’audio. Le volume doit être activé.', rw: 'Kanda 🔊 Voix. Bushobora gutegereza ko ukoraho mbere. Ijwi rigomba kuba ririho.' },
  'help.faq2.q':        { en: 'The mic doesn’t hear me when I say “Jorinova start”', fr: 'Le micro ne m’entend pas quand je dis « Jorinova start »', rw: 'Mikoro ntiyumva iyo mvuze “Jorinova start”' },
  'help.faq2.a':        { en: 'Click 🎤 Listen, then accept the browser permission prompt. The “heard” bar shows what the mic actually picked up. SpeechRecognition needs Chrome or Edge on HTTPS or localhost.', fr: 'Cliquez sur 🎤 Écouter, puis acceptez l’autorisation du navigateur. La barre « entendu » montre ce que le micro a capté. SpeechRecognition nécessite Chrome ou Edge sur HTTPS ou localhost.', rw: 'Kanda 🎤 Listen wemere uruhushya. Bisaba Chrome cyangwa Edge.' },
  'help.faq3.q':        { en: 'My session keeps signing out', fr: 'Ma session se déconnecte sans cesse', rw: 'Igihe cyanjye kirahagarara' },
  'help.faq3.a':        { en: 'The system auto-logs-out after 5 minutes of inactivity for security. Any mouse / key / scroll resets the timer. Sign in again to continue.', fr: 'Le système se déconnecte après 5 minutes d’inactivité pour des raisons de sécurité. Toute action réinitialise le minuteur. Reconnectez-vous pour continuer.', rw: 'Sisitemu isohoka nyuma y’iminota 5 y’ubunebwe. Injira nanone.' },
  'help.faq4.q':        { en: 'Where do I report a bug or request a feature?', fr: 'Où signaler un bug ou demander une fonctionnalité ?', rw: 'Ntanga raporo y’ikosa he?' },
  'help.faq4.a':        { en: 'Email jorinovanexus@gmail.com with a screen recording and the time it happened — we cross-reference with the audit log.', fr: 'Envoyez un e-mail à jorinovanexus@gmail.com avec un enregistrement d’écran et l’heure — nous recoupons avec le journal d’audit.', rw: 'Andikira jorinovanexus@gmail.com.' },

