export type TKey = keyof typeof D

// ── Interpolation: replace {placeholders} with provided vars ──────────────────
function interp(template: string, vars?: Record<string, string | number>): string {
  if (!vars) return template
  return template.replace(/\{(\w+)\}/g, (_, k) =>
    vars[k] != null ? String(vars[k]) : `{${k}}`)
}

/**
 * Translate a key to the given language. Falls back to English if the
 * key is missing for that language; returns the key itself if missing
 * entirely (visible bug marker during dev).
 */
export function translate(lang: Lang, key: TKey, vars?: Record<string, string | number>): string {
  const entry = D[key]
  if (!entry) return key
  const out = entry[lang] ?? entry.en ?? key
  return interp(out, vars)
}

